// Singly-linked list node shape: { val, next }
function reverseKGroup(head, k) {
  let node = head;
  let count = 0;
  while (node && count < k) {
    node = node.next;
    count++;
  }
  if (count < k) return head;
  let prev = reverseKGroup(node, k);
  let cur = head;
  for (let i = 0; i < k; i++) {
    const nxt = cur.next;
    cur.next = prev;
    prev = cur;
    cur = nxt;
  }
  return prev;
}

